import { createContext, useContext, useState } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

export type NotificationProps = Parameters<typeof HTMLHuelNotificationElement.open>[0];

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

export const useNotification = (): [HTMLHuelNotificationElement | null, (props: NotificationProps) => Promise<void>] => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  const notify = async (props: NotificationProps): Promise<void> => {
    if (!notificationElem) return;

    try {
      await notificationElem.open(props);
    } catch (error) {
      setError(error);
    }
  };

  return [notificationElem, notify];
};
